function handleVisibilityChange(t=()=>{},e=()=>{}){document.addEventListener("visibilitychange",()=>{"hidden"===document.visibilityState?t():"visible"===document.visibilityState&&e()})}function timestampToTime(t){const e=new Date(t);return`${e.getFullYear()}-${String(e.getMonth()+1).padStart(2,"0")}-${String(e.getDate()).padStart(2,"0")} ${String(e.getHours()).padStart(2,"0")}:${String(e.getMinutes()).padStart(2,"0")}`}function millisecondToTime(t){const e=Math.floor(t/1e3),i=Math.floor(e/3600),n=Math.ceil(e%3600/60);return`${String(i)}时${String(n).padStart(2,"0")}分`}function millisecondToMinute(t){const e=Math.floor(t/1e3);return Math.floor(e/60).toString()}function millisecondToHour(t){const e=Math.floor(t/1e3)/3600;return e%1==0?e.toString():e.toFixed(1)}function showToast(t,e=3e3){const i=document.getElementById("toast");i.textContent=t,i.classList.add("show"),setTimeout(()=>{i.classList.remove("show")},e)}